// n8n Code node (Run Once for All Items)
// Sin luxon: usa Intl (incluido en Node.js)

const items = $input.all().map(i => i.json);

// Helpers
const normalizeYMD = (v) => {
  if (v === null || v === undefined) return null;
  const s = String(v);
  // si viene ISO: 2026-03-01T00:00:00.000Z => tomamos YYYY-MM-DD
  return s.length >= 10 ? s.slice(0, 10) : s;
};

const ddmmyyyy = (ymd) => {
  if (!ymd) return '';
  const [y, m, d] = ymd.split('-');
  if (!y || !m || !d) return ymd;
  return `${d}-${m}-${y}`;
};

// Para evitar que "YYYY-MM-DD" se corra por zona, usamos mediodía UTC
const dateAtNoonUTC = (ymd) => new Date(`${ymd}T12:00:00.000Z`);

const toTitleCase = (s) =>
  String(s || '').replace(/\p{L}[\p{L}\p{Mn}]*/gu, (w) => w[0].toUpperCase() + w.slice(1));

const fmtDiaES = new Intl.DateTimeFormat('es-CL', {
  weekday: 'long',
  day: 'numeric',
  month: 'long',
  timeZone: 'America/Santiago',
});

const diaTextoES = (ymd) => {
  if (!ymd) return '';
  const raw = fmtDiaES.format(dateAtNoonUTC(ymd)); // ej: "domingo, 1 de marzo"
  return toTitleCase(raw.replace(',', ''));        // "Domingo 1 De Marzo"
};

const hhmm = (t) => {
  if (!t) return '';
  const s = String(t);
  // "11:00:00" => "11:00"
  return s.length >= 5 ? s.slice(0, 5) : s;
};

// Agrupar: Dia -> Depto -> ReservaId -> {reserva, aseo}
const grouped = new Map();

for (const r of items) {
  const dia = normalizeYMD(r.Dia);                 // YYYY-MM-DD
  const depto = r.Depto || 'SinDepto';
  const reservaId = r.ReservaId;

  if (!dia) continue;

  if (!grouped.has(dia)) grouped.set(dia, new Map());
  const byDepto = grouped.get(dia);
  if (!byDepto.has(depto)) byDepto.set(depto, new Map());
  const byReserva = byDepto.get(depto);

  if (!byReserva.has(reservaId)) byReserva.set(reservaId, { reserva: null, aseo: null });
  const obj = byReserva.get(reservaId);

  if (r.ItemTipo === 'RESERVA') obj.reserva = r;
  if (r.ItemTipo === 'ASEO') obj.aseo = r;
}

// Orden
const diasOrdenados = Array.from(grouped.keys()).sort();

// Actualización Chile
const actualizado = new Intl.DateTimeFormat('es-CL', {
  timeZone: 'America/Santiago',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  hour12: false,
}).format(new Date()).replace(',', '');

// Escape HTML
const escapeHtml = (s) =>
  String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');

let body = '';

for (const dia of diasOrdenados) {
  const byDepto = grouped.get(dia);
  const deptosOrdenados = Array.from(byDepto.keys()).sort((a, b) => a.localeCompare(b, 'es'));

  body += `
  <section class="day">
    <div class="dayHeader">
      <div class="dayTitle">${escapeHtml(ddmmyyyy(dia))} · ${escapeHtml(diaTextoES(dia))}</div>
      <div class="daySub">Check-outs y aseos programados</div>
    </div>
  `;

  for (const depto of deptosOrdenados) {
    const byReserva = byDepto.get(depto);
    const reservasOrdenadas = Array.from(byReserva.keys()).sort((a, b) => Number(a) - Number(b));

    body += `
    <div class="deptoCard">
      <div class="deptoHeader">
        <div class="deptoName">Departamento ${escapeHtml(depto)}</div>
      </div>
      <div class="deptoItems">
    `;

    for (const rid of reservasOrdenadas) {
      const { reserva, aseo } = byReserva.get(rid);

      const checkoutHora = reserva ? hhmm(reserva.EventoHora) : '';
      const reservaLabel = reserva?.Reserva_id || reserva?.Reserva__id || `ReservaId ${rid}`;
      const reservaUrl = reserva?.Reserva_reservationUrl || '';

      const aseoId = aseo?.AseoReservaCheckOutId ?? null;
      const aseoHora = aseo ? hhmm(aseo.EventoHora) : '';
      const aseoEstado = aseo?.AseoEstado || '';
      const faltaAseo = !!aseo?.FaltaAseo || !aseoId;

      body += `
        <div class="item">
          <div class="row">
            <div class="tag tagBlue">RESERVA</div>
            <div class="text">
              <div class="main">
                <span class="strong">Check-out</span>
                ${checkoutHora ? `<span class="muted">· ${escapeHtml(checkoutHora)}</span>` : ''}
              </div>
              <div class="sub">
                ${escapeHtml(reservaLabel)}
                ${reservaUrl ? ` · <a class="link" href="${escapeHtml(reservaUrl)}" target="_blank" rel="noopener">Ver</a>` : ''}
              </div>
            </div>
          </div>

          <div class="row">
            <div class="tag ${faltaAseo ? 'tagRed' : 'tagGreen'}">ASEO</div>
            <div class="text">
              <div class="main">
                ${faltaAseo
                  ? `<span class="strong red">FALTA ASEO</span>`
                  : `<span class="strong">Programado</span> ${aseoHora ? `<span class="muted">· ${escapeHtml(aseoHora)}</span>` : ''}`
                }
              </div>
              <div class="sub">
                ${faltaAseo ? 'No hay AseoReservaCheckOut asociado.' : `AseoId ${escapeHtml(aseoId)}${aseoEstado ? ` · ${escapeHtml(aseoEstado)}` : ''}`}
              </div>
            </div>
          </div>
        </div>
      `;
    }

    body += `
      </div>
    </div>
    `;
  }

  body += `</section>`;
}

